12→public class CommentSpacingRule : StandardRule("comment-spacing") {
13→    override fun beforeVisitChildNodes(
14→        node: ASTNode,
15→        autoCorrect: Boolean,
16→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
17→    ) {
18→        if (node.elementType == EOL_COMMENT) {
19→            val prevLeaf = node.prevLeaf()
20→            if (prevLeaf !is PsiWhiteSpace && prevLeaf is LeafPsiElement) {
21→                emit(node.startOffset, "Missing space before //", true)
22→                if (autoCorrect) {
23→                    node.upsertWhitespaceBeforeMe(" ")
24→                }
25→            }
26→            val text = node.getText()
27→            if (text.length != 2 &&
28→                !text.startsWith("// ") &&
29→                !text.startsWith("//noinspection") &&
30→                !text.startsWith("//region") &&
31→                !text.startsWith("//endregion") &&
32→                !text.startsWith("//language=")
33→            ) {
34→                emit(node.startOffset, "Missing space after //", true)
35→                if (autoCorrect) {
36→                    (node as LeafPsiElement).rawReplaceWithText("// " + text.removePrefix("//"))
37→                }
38→            }
39→        }
40→    }
41→}
