{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/NoSingleLineBlockCommentRuleTest.kt", "old_string": "    @Test
    fun `Given single line block comments to disable or enable ktlint then do not reformat`() {
        val code =
            """
            /* ktlint-disable foo-rule-id bar-rule-id */
