!!! tip
    Suppressing a `ktlint` violation is meant primarily as an escape latch for the rare cases when **ktlint** is not able to produce the correct result. Please report any such instances using [GitHub Issues](https://github.com/pinterest/ktlint/issues)).

To disable a specific rule you'll need the rule identifier which is displayed at the end of the lint error.

An error can be suppressed using:

* EOL comments
* Block comments
* @Suppress annotations

=== "[:material-heart:](#) Suppress annotation"

    ```kotlin
    // Suppressing all rules for the entire file
    @file:Suppress("ktlint")

    // Suppress a single rule (with id 'rule-id', defined in rule set with id 'rule-set-id') from the annotated construct
    @Suppress("ktlint:rule-set-id:rule-id")
    class Foo {}

    // Suppress multiple rules for the annotated construct
    @Suppress("ktlint:standard:no-wildcard-imports", "ktlint:custom-rule-set-id:custom-rule-id")
    import foo.*

    // Suppress all rules for the annotated construct
    @Suppress("ktlint")
    import foo.*
    ```
=== "[:material-heart:](#) EOL comments"

    ```kotlin
    // Suppress a single rule for the commented line
    import foo.* // ktlint-disable standard_no-wildcard-imports

    // Suppress multiple rules for the commented line
    import foo.* // ktlint-disable standard_no-wildcard-imports standard_other-rule-id

    // Suppress all rules for the commented line
    import foo.* // ktlint-disable
    ```

=== "[:material-heart-off-outline:](#) Block comments"

    ```kotlin
    // Suppress a single rule for all code between the start and end tag
    /* ktlint-disable standard_no-wildcard-imports */
    import foo.*
    /* ktlint-disable standard_no-wildcard-imports */

    // Suppress multiple rules for all code between the start and end tag
    /* ktlint-disable standard_no-wildcard-imports standard_no-wildcard-imports */
    import foo.*
    /* ktlint-enable standard_no-wildcard-imports standard_no-wildcard-imports */

    // Suppress all rules for all code between the start and end tag
    /* ktlint-disable */
    import foo.*
    /* ktlint-enable */
    ```

!!! important
    When using the block comments, the `ktlint-enable` directive needs to specify the exact same rule-id's and in the same order as the `ktlint-disable` directive.

!!! warning
    From a consistency perspective seen, it might be best to **not** mix the (EOL/Block) comment style with the annotation style in the same project.", "new_string": "## How do I suppress errors for a line/block/file?

!!! tip
    Suppressing a `ktlint` violation is meant primarily as an escape latch for the rare cases when **ktlint** is not able to produce the correct result. Please report any such instances using [GitHub Issues](https://github.com/pinterest/ktlint/issues)).

To disable a specific rule you'll need the rule identifier which is displayed at the end of the lint error.

An error can be suppressed using `@Suppress` annotations:

```kotlin
// Suppressing all rules for the entire file
@file:Suppress("ktlint")

// Suppress a single rule (with id 'rule-id', defined in rule set with id 'rule-set-id') from the annotated construct
@Suppress("ktlint:rule-set-id:rule-id")
class Foo {}

// Suppress multiple rules for the annotated construct
@Suppress("ktlint:standard:no-wildcard-imports", "ktlint:custom-rule-set-id:custom-rule-id")
import foo.*

// Suppress all rules for the annotated construct
@Suppress("ktlint")
import foo.*
```

!!! warning "Deprecated directives"
    The `ktlint-disable` and `ktlint-enable` comment-based directives have been removed as of KtLint version `1.0`. Use `@Suppress` annotations instead.

    A new rule `no-deprecated-ktlint-directive` detects the usage of deprecated directives and reports them."}

{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/NoDeprecatedKtlintDirectiveRuleTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class NoDeprecatedKtlintDirectiveRuleTest {
    private val noDeprecatedKtlintDirectiveRuleAssertThat =
        KtLintAssertThat.assertThatRule { NoDeprecatedKtlintDirectiveRule() }

    @Test
    fun `Given code with EOL ktlint-disable directive then report violation`() {
        val code =
            """
            val foo = "foo" // ktlint-disable
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code)
            .hasLintViolation(1, 17, "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead")
    }

    @Test
    fun `Given code with EOL ktlint-disable directive for specific rule then report violation`() {
        val code =
            """
            val foo = "foo" // ktlint-disable standard:no-wildcard-imports
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code)
            .hasLintViolation(1, 17, "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead")
    }

    @Test
    fun `Given code with block ktlint-disable directive then report violation`() {
        val code =
            """
            /* ktlint-disable */
            val foo = "foo"
            /* ktlint-enable */
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code)
            .hasLintViolations(
                KtLintAssertThat.LintViolation(1, 1, "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead"),
                KtLintAssertThat.LintViolation(3, 1, "Directive 'ktlint-enable' is deprecated. Use @Suppress annotation instead"),
            )
    }

    @Test
    fun `Given code with block ktlint-disable directive for specific rule then report violation`() {
        val code =
            """
            /* ktlint-disable standard:no-wildcard-imports */
            val foo = "foo"
            /* ktlint-enable standard:no-wildcard-imports */
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code)
            .hasLintViolations(
                KtLintAssertThat.LintViolation(1, 1, "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead"),
                KtLintAssertThat.LintViolation(3, 1, "Directive 'ktlint-enable' is deprecated. Use @Suppress annotation instead"),
            )
    }

    @Test
    fun `Given code with Suppress annotation then do not report violation`() {
        val code =
            """
            @Suppress("ktlint")
            val foo = "foo"
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given code with regular comment containing ktlint text but not a directive then do not report violation`() {
        val code =
            """
            // This comment mentions ktlint-disable but is not a directive
            val foo = "foo"
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given code without any directives then do not report violation`() {
        val code =
            """
            val foo = "foo"
            val bar = "bar"
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

