{"file_path": "/project/ktlint-ruleset-standard/src/main/kotlin/com/pinterest/ktlint/ruleset/standard/rules/NoDeprecatedKtlintDirectiveRule.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.ElementType.BLOCK_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.ElementType.EOL_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode

/**
 * Detects deprecated ktlint directive comments (ktlint-disable, ktlint-enable) and reports them.
 *
 * Starting from version 1.0, ktlint no longer supports comment-based suppression directives.
 * Use `@Suppress` annotations instead:
 * - `@Suppress("ktlint")` to suppress all ktlint rules
 * - `@Suppress("ktlint:rule-id")` to suppress a specific rule
 * - `@file:Suppress("ktlint")` to suppress rules for the entire file
 */
public class NoDeprecatedKtlintDirectiveRule : StandardRule("no-deprecated-ktlint-directive") {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        when (node.elementType) {
            EOL_COMMENT -> {
                checkEolComment(node, emit)
            }
            BLOCK_COMMENT -> {
                checkBlockComment(node, emit)
            }
        }
    }

    private fun checkEolComment(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val text =
            node.text
                .removePrefix("//")
                .trim()
        if (text.startsWith(KTLINT_DISABLE)) {
            emit(
                node.startOffset,
                "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead",
                false,
            )
        }
    }

    private fun checkBlockComment(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val text =
            node.text
                .removePrefix("/*")
                .removeSuffix("*/")
                .trim()
        when {
            text.startsWith(KTLINT_DISABLE) -> {
                emit(
                    node.startOffset,
                    "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead",
                    false,
                )
            }
            text.startsWith(KTLINT_ENABLE) -> {
                emit(
                    node.startOffset,
                    "Directive 'ktlint-enable' is deprecated. Use @Suppress annotation instead",
                    false,
                )
            }
        }
    }

    private companion object {
        const val KTLINT_DISABLE = "ktlint-disable"
        const val KTLINT_ENABLE = "ktlint-enable"
    }
}

public val NO_DEPRECATED_KTLINT_DIRECTIVE_RULE_ID: RuleId = NoDeprecatedKtlintDirectiveRule().ruleId
"}

