class NoDeprecatedKtlintDirectiveRuleTest {
    private val noDeprecatedKtlintDirectiveRuleAssertThat =
        KtLintAssertThat.assertThatRule { NoDeprecatedKtlintDirectiveRule() }

    @Test
    fun `Given code with EOL ktlint-disable directive then report violation`() {
        val code =
            """
            val foo = "foo" // ktlint-disable
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code)
            .hasLintViolation(1, 17, "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead")
    }

    @Test
    fun `Given code with EOL ktlint-disable directive for specific rule then report violation`() {
        val code =
            """
            val foo = "foo" // ktlint-disable standard:no-wildcard-imports
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code)
            .hasLintViolation(1, 17, "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead")
    }

    @Test
    fun `Given code with block ktlint-disable directive then report violation`() {
        val code =
            """
            /* ktlint-disable */
            val foo = "foo"
            /* ktlint-enable */
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code)
            .hasLintViolations(
                KtLintAssertThat.LintViolation(1, 1, "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead"),
                KtLintAssertThat.LintViolation(3, 1, "Directive 'ktlint-enable' is deprecated. Use @Suppress annotation instead"),
            )
    }

    @Test
    fun `Given code with block ktlint-disable directive for specific rule then report violation`() {
        val code =
            """
            /* ktlint-disable standard:no-wildcard-imports */
            val foo = "foo"
            /* ktlint-enable standard:no-wildcard-imports */
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code)
            .hasLintViolations(
                KtLintAssertThat.LintViolation(1, 1, "Directive 'ktlint-disable' is deprecated. Use @Suppress annotation instead"),
                KtLintAssertThat.LintViolation(3, 1, "Directive 'ktlint-enable' is deprecated. Use @Suppress annotation instead"),
            )
    }

    @Test
    fun `Given code with Suppress annotation then do not report violation`() {
        val code =
            """
            @Suppress("ktlint")
            val foo = "foo"
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given code with regular comment containing ktlint text but not a directive then do not report violation`() {
        val code =
            """
            // This comment mentions ktlint-disable but is not a directive
            val foo = "foo"
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given code without any directives then do not report violation`() {
        val code =
            """
            val foo = "foo"
            val bar = "bar"
            """.trimIndent()
        noDeprecatedKtlintDirectiveRuleAssertThat(code).hasNoLintViolations()
    }
}
